/**
 * @fileoverview Combobox component definition for JIT pipeline.
 *
 * @module module/Combobox.def
 */

import razyui from '../index.js';
import { PART } from './Combobox/constants.js';

/**
 * The definition object for the Combobox component.
 * @type {Object}
 */
export const ComboboxDef = {
    name: 'Combobox',
    tag: 'rui-combobox',

    tokens: {
        prefix: 'cb',
        tokens: {
            'radius':          { ref: 'radius.sm',          description: 'Container border radius' },
            'padding':         { value: '0.5rem 0.75rem',   description: 'Control padding' },
            'font-size':       { ref: 'font.size-sm',       description: 'Font size' },
            'line-height':     { value: '1.25',             description: 'Line height' },
            'gap':             { value: '0.25rem',          description: 'Internal gap' },
            'min-height':      { value: 'calc(2.0625rem + 2px)', description: 'Minimum height' },
            'accent':          { ref: 'color.accent',       description: 'Focus accent color' },
            'accent-subtle':   { ref: 'color.accent-subtle', description: 'Focus ring color' },
            'bg':              { ref: 'color.bg',           description: 'Background' },
            'bg-hover':        { ref: 'color.bg-hover',     description: 'Hover background' },
            'bg-inset':        { ref: 'color.bg-inset',     description: 'Disabled background' },
            'bg-raised':       { ref: 'color.bg-raised',    description: 'Raised background' },
            'border':          { ref: 'color.border',       description: 'Border color' },
            'border-strong':   { ref: 'color.border-strong', description: 'Hover border' },
            'control-px':      { value: '0.75rem',          description: 'Control horizontal padding' },
            'control-py':      { value: '0.5rem',           description: 'Control vertical padding' },
            'danger':          { ref: 'color.danger',       description: 'Danger color' },
            'font-stack':      { ref: 'font.family',        description: 'Font family' },
            'overlay':         { ref: 'color.overlay',      description: 'Overlay backdrop' },
            'shadow-lg':       { ref: 'shadow.lg',          description: 'Dropdown shadow' },
            'space-lg':        { ref: 'spacing.6',          description: 'Large spacing' },
            'space-md':        { ref: 'spacing.4',          description: 'Medium spacing' },
            'space-sm':        { ref: 'spacing.2',          description: 'Small spacing' },
            'text':            { ref: 'color.text',         description: 'Text color' },
            'text-muted':      { ref: 'color.text-muted',   description: 'Muted text' },
            'text-secondary':  { ref: 'color.text-secondary', description: 'Secondary text' },
        },
    },

    states: {
        initial: 'closed',
        states: {
            closed:   { on: { OPEN: 'open' } },
            open:     { on: { CLOSE: 'closed', SELECT: 'closed' } },
            disabled: { on: { ENABLE: 'closed' } },
        },
        effects: {
            open(ctx) {
                if (ctx.container) razyui(ctx.container).addClass('is-open');
            },
            closed(ctx) {
                if (ctx.container) razyui(ctx.container).removeClass('is-open');
            },
            disabled(ctx) {
                if (ctx.container) razyui(ctx.container).addClass('is-disabled');
            },
            'disabled:exit'(ctx) {
                if (ctx.container) razyui(ctx.container).removeClass('is-disabled');
            },
        },
    },

    template: {
        slots: {
            wrapper:   { element: 'div', classes: ['combobox-wrapper'] },
            container: { element: 'div', classes: ['combobox-container'] },
            display:   { element: 'span', classes: ['combobox-display'] },
            dropdown:  { element: 'div', classes: ['combobox-options'] },
            option:    { element: 'div', classes: ['combobox-option'] },
        },
    },

    variants: {
        rich: { description: 'Rich option templates with icons/descriptions' },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.LABEL]: PART.LABEL,
        [PART.CHEVRON]: PART.CHEVRON,
        [PART.FLOATING]: PART.FLOATING,
        [PART.FILTER]: PART.FILTER,
        [PART.OPTIONS]: PART.OPTIONS,
        [PART.ITEM]: PART.ITEM,
        [PART.ITEM_TEXT]: PART.ITEM_TEXT,
        [PART.ITEM_CONTENT]: PART.ITEM_CONTENT,
        [PART.CHECK]: PART.CHECK,
        [PART.GROUP]: PART.GROUP,
        [PART.CHECKBOX]: PART.CHECKBOX,
        [PART.EXPAND]: PART.EXPAND,
        [PART.OVERLAY]: PART.OVERLAY,
        [PART.DARKROOM]: PART.DARKROOM,
        [PART.DARKROOM_HEADER]: PART.DARKROOM_HEADER,
        [PART.DARKROOM_CLOSE]: PART.DARKROOM_CLOSE,
        [PART.DARKROOM_BODY]: PART.DARKROOM_BODY,
        [PART.TITLE]: PART.TITLE,
        [PART.META]: PART.META,
        [PART.AC_INPUT]: PART.AC_INPUT,
    },

    styles: {
        // Check visibility: show checkmark only on selected items (static CSS avoids fragile JIT [&_...] descendant selectors)
        '&-item.is-selected &-check::after': 'opacity: 1',
    },

    observedAttrs: ['value', 'disabled', 'readonly', 'placeholder', 'autocomplete'],
    attrMap: {
        value: 'value',
        disabled: 'disabled',
        readonly: 'readonly',
        placeholder: 'placeholder',
        autocomplete: 'autocomplete',
    },
};

export default ComboboxDef;
